// Extract L1 assets and fan out one message per asset to fetch their children
const response = msg.payload || {};
const assets = response._embedded?.assets || response._embedded?.asset || [];

if (assets.length === 0) {
    node.warn('No L1 assets found');
    return null;
}

// Return an array of messages - Node-RED sends each as a separate message
// msg.parts tells the downstream join node how many to expect
const msgs = assets.map((asset, i) => ({
    payload: asset,
    mindspherePath: `/api/assetmanagement/v3/assets?filter={"parentId":"${asset.assetId}"}`,
    parts: { id: msg._msgid, index: i, count: assets.length, type: 'array' }
}));

return [msgs];

// Store the asset mapping in flow variable for use in other parts
const assetMap = msg.payload.assetMap || {};
const assetsList = msg.payload.assetsList || [];

flow.set('assetNameToIdMap', assetMap);
flow.set('assetsList', assetsList);

msg.payload = {
    message: 'Asset mapping stored in flow variables',
    totalAssets: Object.keys(assetMap).length,
    assetNames: Object.keys(assetMap),
    mapping: assetMap
};

return msg;

// msg.payload is an array of HTTP responses, one per L1 asset queried
const responses = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
const mapping = {};
const namesList = [];

responses.forEach(response => {
    const assets = response._embedded?.assets || response._embedded?.asset || [];
    assets.forEach(asset => {
        if (asset.name && asset.assetId) {
            mapping[asset.name] = asset.assetId;
            namesList.push({
                name: asset.name,
                assetId: asset.assetId,
                typeId: asset.typeId,
                parentId: asset.parentId
            });
        }
    });
});

msg.payload = {
    assetMap: mapping,
    assetsList: namesList,
    totalCount: namesList.length
};

return msg;
